#nullable enable // autogenerated

using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Level;
using PVZEngine.Modifiers;

namespace MVZ2.GameContent.Buffs.SeedPacks
{
    [AutoBuffDefinition(VanillaBuffNames.SeedPack.controlRodRecharge)]
    public class ControlRodRechargeBuff : BuffDefinition
    {
        public ControlRodRechargeBuff(string nsp, string name) : base(nsp, name)
        {
            AddModifier(new FloatModifier(EngineSeedProps.RECHARGE_SPEED, NumberOperator.Multiply, 1.5f));
        }
    }
}
